import React, { useEffect, useRef } from 'react'
import useStore, { applyTheme } from './store/useStore'
import { get, post } from './lib/api'
import { WSClient } from './lib/ws'
import { callManager } from './lib/webrtc'
import AuthPage from './pages/AuthPage'
import MainPage from './pages/MainPage'
import ToastContainer from './components/ToastContainer'
import IncomingCallModal from './components/calls/IncomingCallModal'
import ActiveCallWindow from './components/calls/ActiveCallWindow'

let wsInstance = null

export default function App() {
  const { token, me, setAuth, logout, setWsConnected, addToast,
    appendMessage, updateMessage, deleteMessage, updateConvLastMessage,
    incrementUnread, activeConvId, setTyping, setIncomingCall,
    activeCall, setActiveCall, incomingCall, updateMe, conversations,
    appendChannelMessage, activeChannelId } = useStore()

  const wsRef = useRef(null)
  const pingRef = useRef(null)

  useEffect(() => {
    applyTheme('violet')
    ;(async () => {
      try {
        let cfg = {}
        if (window.electron) {
          cfg = await window.electron.config.load() || {}
        } else {
          const saved = localStorage.getItem('omni_session')
          cfg = saved ? JSON.parse(saved) : {}
        }
        if (cfg.token) {
          const res = await get('/api/auth/me', { token: cfg.token })
          if (res.ok) {
            setAuth(cfg.token, res.data)
            applyTheme(res.data.theme || 'violet')
          } else {
            localStorage.removeItem('omni_session')
          }
        }
      } catch {}
    })()
  }, [])

  useEffect(() => {
    if (!token) {
      wsInstance?.disconnect()
      wsInstance = null
      wsRef.current = null
      clearInterval(pingRef.current)
      return
    }

    const ws = new WSClient({
      onConnect: () => setWsConnected(true),
      onDisconnect: () => setWsConnected(false),
      onMessage: (msg) => handleWsMessage(msg),
    })
    ws.connect(token)
    wsInstance = ws
    wsRef.current = ws
    pingRef.current = setInterval(() => ws.send({ type: 'ping' }), 30000)

    return () => {
      ws.disconnect()
      clearInterval(pingRef.current)
    }
  }, [token])

  function handleWsMessage(msg) {
    const store = useStore.getState()

    switch (msg.type) {
      case 'new_message': {
        const { conversationId, message } = msg
        store.appendMessage(conversationId, message)
        store.updateConvLastMessage(conversationId, message)
        if (conversationId !== store.activeConvId) {
          store.incrementUnread(conversationId)
          if (message.sender?.id !== store.me?.id) {
            const body = message.type === 'audio' ? '🎤 Голосовое сообщение'
              : message.type === 'image' ? '🖼 Фото'
              : message.type === 'video' ? '🎬 Видео'
              : message.type === 'file' ? '📎 Файл'
              : message.content
            store.addToast({
              title: message.sender?.displayName || message.sender?.username,
              body,
              type: 'message',
            })
            window.electron?.notify({
              title: message.sender?.displayName || message.sender?.username,
              body: body?.slice(0, 80),
            })
          }
        }
        break
      }
      case 'message_edited': {
        const { conversationId, messageId, content } = msg
        store.updateMessage(conversationId, messageId, { content, edited: true })
        break
      }
      case 'message_deleted': {
        const { conversationId, messageId } = msg
        store.deleteMessage(conversationId, messageId)
        break
      }
      case 'message_reaction': {
        const { conversationId, messageId, reactions } = msg
        store.updateMessage(conversationId, messageId, { reactions })
        break
      }
      case 'typing': {
        const { conversationId, username } = msg
        const cur = store.typing[conversationId] || []
        if (!cur.includes(username)) {
          store.setTyping(conversationId, [...cur, username])
          setTimeout(() => {
            const now = useStore.getState().typing[conversationId] || []
            store.setTyping(conversationId, now.filter(u => u !== username))
          }, 3000)
        }
        break
      }
      case 'incoming_call': {
        store.setIncomingCall(msg)
        break
      }
      case 'call_accepted': {
        callManager.setRemoteAnswer(msg.answer)
        store.setActiveCall(prev => prev ? { ...prev, state: 'connected', startTime: Date.now() } : null)
        break
      }
      case 'call_rejected': {
        callManager.hangup()
        store.setActiveCall(null)
        store.addToast({ title: 'Звонок', body: 'Собеседник отклонил звонок', type: 'info' })
        break
      }
      case 'call_ended': {
        callManager.hangup()
        store.setActiveCall(null)
        break
      }
      case 'call_unavailable': {
        callManager.hangup()
        store.setActiveCall(null)
        store.addToast({ title: 'Звонок', body: 'Пользователь недоступен', type: 'info' })
        break
      }
      case 'call_ice': {
        callManager.addIceCandidate(msg.candidate)
        break
      }
      case 'coins_added': {
        store.updateMe({ coins: msg.coins })
        store.addToast({ title: '💰 Монеты', body: `Начислено ${msg.amount} монет`, type: 'success' })
        break
      }
      case 'premium_activated': {
        store.updateMe({ isPremium: true, premiumUntil: msg.until })
        store.addToast({ title: '⭐ Premium', body: 'Premium активирован!', type: 'success' })
        break
      }
      case 'force_logout': {
        store.addToast({ title: 'Сессия завершена', body: msg.reason || '', type: 'error' })
        setTimeout(() => store.logout(), 2000)
        break
      }
      case 'account_frozen': {
        store.addToast({ title: '❄️ Аккаунт заморожен', body: msg.reason || '', type: 'error' })
        setTimeout(() => store.logout(), 3000)
        break
      }
      case 'account_muted': {
        store.addToast({ title: '🔇 Вы замьючены', body: `До ${msg.until || 'снятия'}`, type: 'warning' })
        break
      }
      case 'new_channel_message': {
        const { channelId, message } = msg
        store.appendChannelMessage(channelId, message)
        break
      }
    }
  }

  function getWs() { return wsRef.current }

  return (
    <>
      {!token
        ? <AuthPage />
        : <MainPage getWs={getWs} />
      }
      <ToastContainer />
      {incomingCall && <IncomingCallModal call={incomingCall} getWs={getWs} />}
      {activeCall && <ActiveCallWindow getWs={getWs} />}
    </>
  )
}

import React, { useState, useEffect } from 'react'
import useStore from '../../store/useStore'
import { callManager } from '../../lib/webrtc'
import Avatar from '../Avatar'
import styles from './ActiveCallWindow.module.css'

export default function ActiveCallWindow({ getWs }) {
  const { activeCall, setActiveCall, addToast } = useStore()
  const [muted, setMuted] = useState(false)
  const [elapsed, setElapsed] = useState(0)

  useEffect(() => {
    if (activeCall?.state !== 'connected') return
    const t = setInterval(() => setElapsed(s => s + 1), 1000)
    return () => clearInterval(t)
  }, [activeCall?.state])

  function toggleMute() {
    const m = callManager.toggleMute()
    setMuted(m)
  }

  function endCall() {
    const ws = getWs()
    if (ws && activeCall) {
      ws.send({ type: 'call_end', targetUserId: activeCall.peerId, callId: activeCall.callId })
    }
    callManager.hangup()
    setActiveCall(null)
  }

  if (!activeCall) return null

  const fmtElapsed = () => {
    const m = Math.floor(elapsed / 60).toString().padStart(2, '0')
    const s = (elapsed % 60).toString().padStart(2, '0')
    return `${m}:${s}`
  }

  return (
    <div className={styles.window}>
      <div className={styles.header}>
        <div className={styles.avatarWrap}>
          <Avatar name={activeCall.peerName} size={40} />
          {activeCall.state === 'connected' && <div className={styles.activeDot} />}
        </div>
        <div className={styles.info}>
          <span className={styles.name}>{activeCall.peerName}</span>
          <span className={styles.status}>
            {activeCall.state === 'calling'
              ? <><span className={styles.pulse} />Дозваниваемся...</>
              : activeCall.state === 'connected'
              ? <>🟢 {fmtElapsed()}</>
              : activeCall.state}
          </span>
        </div>
        <div className={styles.controls}>
          <button
            className={`${styles.ctrl} ${muted ? styles.ctrlMuted : ''}`}
            onClick={toggleMute}
            title={muted ? 'Включить микрофон' : 'Выключить микрофон'}
          >
            {muted
              ? <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="1" y1="1" x2="23" y2="23"/><path d="M9 9v3a3 3 0 005.12 2.12M15 9.34V4a3 3 0 00-5.94-.6"/><path d="M17 16.95A7 7 0 015 12v-2m14 0v2a7 7 0 01-.11 1.23M12 19v4M8 23h8"/></svg>
              : <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z"/><path d="M19 10v2a7 7 0 01-14 0v-2M12 19v4M8 23h8"/></svg>
            }
          </button>
          <button className={styles.endBtn} onClick={endCall} title="Завершить звонок">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <path d="M10.68 13.31a16 16 0 003.41 2.6l1.27-1.27a2 2 0 012.11-.45 12.84 12.84 0 002.81.7 2 2 0 011.72 2v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07 19.42 19.42 0 01-3.33-2.67m-2.67-3.34a19.79 19.79 0 01-3.07-8.63A2 2 0 014.11 2h3a2 2 0 012 1.72 12.84 12.84 0 00.7 2.81 2 2 0 01-.45 2.11L8.09 9.91"/>
              <line x1="23" y1="1" x2="1" y2="23"/>
            </svg>
          </button>
        </div>
      </div>
    </div>
  )
}

import React, { useEffect, useRef } from 'react'
import { callManager } from '../../lib/webrtc'
import useStore from '../../store/useStore'
import Avatar from '../Avatar'
import styles from './IncomingCallModal.module.css'

export default function IncomingCallModal({ call, getWs }) {
  const { setIncomingCall, setActiveCall, addToast } = useStore()
  const callerName = call.callerName || call.callerId
  const ringRef = useRef(null)

  useEffect(() => {
    try {
      const ctx = new AudioContext()
      let t = ctx.currentTime
      const ring = () => {
        const o = ctx.createOscillator()
        const g = ctx.createGain()
        o.connect(g); g.connect(ctx.destination)
        o.frequency.setValueAtTime(880, t)
        g.gain.setValueAtTime(0.3, t)
        g.gain.exponentialRampToValueAtTime(0.001, t + 0.4)
        o.start(t); o.stop(t + 0.4)
        t += 0.8
      }
      for (let i = 0; i < 20; i++) ring()
      ringRef.current = ctx
    } catch {}
    return () => { try { ringRef.current?.close() } catch {} }
  }, [])

  async function accept() {
    try { ringRef.current?.close() } catch {}
    const ws = getWs()
    if (!ws) return
    try {
      await callManager.answerCall(ws, call.callerId, call.callId, call.offer)
      setActiveCall({ peerId: call.callerId, peerName: callerName, callId: call.callId, state: 'connected', startTime: Date.now() })
      setIncomingCall(null)
    } catch (err) {
      addToast({ title: 'Звонок', body: err.message || 'Ошибка подключения', type: 'error' })
      setIncomingCall(null)
    }
  }

  function reject() {
    try { ringRef.current?.close() } catch {}
    const ws = getWs()
    ws?.send({ type: 'call_reject', callerId: call.callerId, callId: call.callId })
    setIncomingCall(null)
  }

  return (
    <div className={styles.overlay}>
      <div className={styles.modal}>
        <div className={styles.ring}>
          <span>📞</span>
        </div>
        <Avatar name={callerName} size={72} />
        <div className={styles.name}>{callerName}</div>
        <div className={styles.sub}>Входящий голосовой звонок</div>
        <div className={styles.actions}>
          <button className={styles.rejectBtn} onClick={reject}>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <path d="M10.68 13.31a16 16 0 003.41 2.6l1.27-1.27a2 2 0 012.11-.45 12.84 12.84 0 002.81.7 2 2 0 011.72 2v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07 19.42 19.42 0 01-3.33-2.67m-2.67-3.34a19.79 19.79 0 01-3.07-8.63A2 2 0 014.11 2h3a2 2 0 012 1.72 12.84 12.84 0 00.7 2.81 2 2 0 01-.45 2.11L8.09 9.91"/>
              <line x1="23" y1="1" x2="1" y2="23"/>
            </svg>
            <span>Отклонить</span>
          </button>
          <button className={styles.acceptBtn} onClick={accept}>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <path d="M22 16.92v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07A19.5 19.5 0 013.59 10.59 19.79 19.79 0 01.5 2a2 2 0 012-2h3a2 2 0 012 1.72 12.84 12.84 0 00.7 2.81 2 2 0 01-.45 2.11L6.6 7.84a16 16 0 006.59 6.59l1.18-1.18a2 2 0 012.11-.45 12.84 12.84 0 002.81.7A2 2 0 0122 16.92z"/>
            </svg>
            <span>Принять</span>
          </button>
        </div>
      </div>
    </div>
  )
}

.window {
  position: fixed;
  bottom: 24px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: 20px;
  box-shadow: 0 12px 40px rgba(0,0,0,0.6);
  z-index: 8000;
  animation: slideUp 0.3s cubic-bezier(0.34,1.56,0.64,1);
  overflow: hidden;
  min-width: 320px;
  backdrop-filter: blur(12px);
}

@keyframes slideUp {
  from { opacity: 0; transform: translateX(-50%) translateY(30px) scale(0.9); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0)   scale(1); }
}

.header {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 16px 20px;
}

.avatarWrap {
  position: relative;
  flex-shrink: 0;
}

.activeDot {
  position: absolute;
  bottom: 0; right: 0;
  width: 11px; height: 11px;
  border-radius: 50%;
  background: #22c55e;
  border: 2px solid var(--bg2);
  animation: pulseGreen 2s infinite;
}

@keyframes pulseGreen {
  0%,100% { box-shadow: 0 0 0 0 rgba(34,197,94,0.4); }
  50%      { box-shadow: 0 0 0 6px rgba(34,197,94,0); }
}

.info { flex: 1; overflow: hidden; }

.name {
  display: block;
  font-size: 15px;
  font-weight: 600;
  color: var(--text);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.status {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 12px;
  color: var(--text3);
  margin-top: 2px;
}

.pulse {
  display: inline-block;
  width: 7px; height: 7px;
  border-radius: 50%;
  background: var(--accent);
  animation: blink 1.2s infinite;
}

@keyframes blink {
  0%,100% { opacity: 1; }
  50%      { opacity: 0.2; }
}

.controls {
  display: flex;
  gap: 8px;
  align-items: center;
}

.ctrl {
  width: 38px; height: 38px;
  border-radius: 12px;
  background: var(--bg4);
  color: var(--text2);
  display: flex; align-items: center; justify-content: center;
  transition: all 0.15s;
}
.ctrl:hover { background: var(--bg5); color: var(--text); }
.ctrlMuted  { background: rgba(239,68,68,0.15); color: #ef4444; }
.ctrlMuted:hover { background: rgba(239,68,68,0.25); }

.endBtn {
  width: 38px; height: 38px;
  border-radius: 12px;
  background: #ef4444;
  color: #fff;
  display: flex; align-items: center; justify-content: center;
  transition: background 0.15s, transform 0.1s;
}
.endBtn:hover  { background: #dc2626; }
.endBtn:active { transform: scale(0.93); }

.overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.75);
  backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9000;
  animation: fadeIn 0.2s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

.modal {
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: 28px;
  padding: 36px 32px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  min-width: 280px;
  box-shadow: 0 24px 80px rgba(0,0,0,0.7);
  animation: popIn 0.35s cubic-bezier(0.34,1.56,0.64,1);
}

@keyframes popIn {
  from { opacity: 0; transform: scale(0.8) translateY(20px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

