.overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.75);
  backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9000;
  animation: fadeIn 0.2s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

.modal {
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: 28px;
  padding: 36px 32px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  min-width: 280px;
  box-shadow: 0 24px 80px rgba(0,0,0,0.7);
  animation: popIn 0.35s cubic-bezier(0.34,1.56,0.64,1);
}

@keyframes popIn {
  from { opacity: 0; transform: scale(0.8) translateY(20px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

.ring {
  font-size: 40px;
  animation: ring 0.6s ease infinite alternate;
}

@keyframes ring {
  from { transform: rotate(-15deg); }
  to   { transform: rotate(15deg); }
}

.name {
  font-size: 20px;
  font-weight: 700;
  color: var(--text);
  margin-top: 4px;
}

.sub {
  font-size: 13px;
  color: var(--text3);
  margin-bottom: 4px;
}

.actions {
  display: flex;
  gap: 24px;
  margin-top: 12px;
}

.rejectBtn, .acceptBtn {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 6px;
  width: 68px;
  height: 68px;
  border-radius: 50%;
  font-size: 11px;
  font-weight: 600;
  transition: all 0.15s;
}

.rejectBtn {
  background: rgba(239,68,68,0.18);
  color: #ef4444;
}
.rejectBtn:hover { background: rgba(239,68,68,0.32); transform: scale(1.08); }
.rejectBtn:active { transform: scale(0.95); }

.acceptBtn {
  background: #22c55e;
  color: #fff;
}
.acceptBtn:hover { background: #16a34a; transform: scale(1.08); }
.acceptBtn:active { transform: scale(0.95); }

