  border: 1px solid var(--border);
  border-radius: 8px;
  font-size: 13px;
  color: var(--text);
}
.gifSearchInput:focus { border-color: var(--accent); outline: none; }
.gifSearchInput::placeholder { color: var(--text3); }

.gifGrid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
  padding: 6px 10px 10px;
  overflow-y: auto;
  flex: 1;
}

.gifItem {
  border-radius: 8px;
  overflow: hidden;
  aspect-ratio: 16/9;
  background: var(--bg4);
  transition: transform 0.15s, opacity 0.15s;
}
.gifItem:hover { transform: scale(1.03); opacity: 0.9; }
.gifItem img { width: 100%; height: 100%; object-fit: cover; display: block; }

.gifLoading {
  grid-column: 1 / -1;
  color: var(--text3);
  font-size: 13px;
  text-align: center;
  padding: 20px;
}

/* ── Image attachment ── */
.imgWrap {
  position: relative;
  cursor: pointer;
  overflow: hidden;
  border-radius: 14px;
  max-width: 280px;
  min-width: 140px;
}

.imgSkeleton {
  width: 100%;
  height: 180px;
  background: var(--bg5);
  border-radius: 14px;
  animation: shimmer 1.5s infinite;
}
@keyframes shimmer {
  0%   { opacity: 0.5; }
  50%  { opacity: 1; }
  100% { opacity: 0.5; }
}

.imgAttach {
  display: block;
  width: 100%;
  max-height: 320px;
  object-fit: cover;
  border-radius: 14px;
  opacity: 0;
  transition: opacity 0.2s;
}
.imgLoaded { opacity: 1; }

.imgOverlay {
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.3);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.2s;
  border-radius: 14px;
  color: #fff;
}
.imgWrap:hover .imgOverlay { opacity: 1; }

/* ── Video attachment ── */
.videoWrap {
  position: relative;
  border-radius: 14px;
  overflow: hidden;
  max-width: 300px;
  background: #000;
  cursor: pointer;
}

.videoAttach {
  width: 100%;
  max-height: 220px;
  display: block;
  object-fit: cover;
}

.videoOverlay {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0,0,0,0.25);
  transition: background 0.2s;
}
.videoPlaying { background: rgba(0,0,0,0.05); }
.videoPlaying .playBtn { display: none; }

.playBtn {
  width: 52px; height: 52px;
  border-radius: 50%;
  background: rgba(0,0,0,0.65);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  transition: transform 0.15s, background 0.15s;
}
.videoWrap:hover .playBtn { background: rgba(0,0,0,0.8); transform: scale(1.08); }

.videoName {
  position: absolute;
  bottom: 32px;
  left: 8px;
  right: 8px;
  font-size: 11px;
  color: rgba(255,255,255,0.8);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.videoControls {
  position: absolute;
  bottom: 0;
  left: 0; right: 0;
  display: flex;
  gap: 4px;
  padding: 4px 6px;
  background: rgba(0,0,0,0.55);
}

.videoCtrlBtn {
  width: 24px; height: 24px;
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  text-decoration: none;
  font-size: 11px;
  transition: background 0.15s;
}
.videoCtrlBtn:hover { background: rgba(255,255,255,0.2); }

/* ── Voice bubble ── */
.voiceBubble {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  min-width: 200px;
  max-width: 280px;
}
.voiceBubbleMe .voicePlayBtn { background: rgba(255,255,255,0.2); color: #fff; }
.voiceBubbleMe .voicePlayBtn:hover { background: rgba(255,255,255,0.3); }

.voicePlayBtn {
  width: 36px; height: 36px;
  border-radius: 50%;
  background: var(--accent);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: background 0.15s, transform 0.1s;
}
.voicePlayBtn:hover { transform: scale(1.08); }

.voiceTrack {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 4px;
  cursor: pointer;
}

.voiceBar {
  height: 28px;
  display: flex;
  align-items: center;
  gap: 2px;
  position: relative;
}

.voiceProgress {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  pointer-events: none;
}

.voiceWave {
  width: 3px;
  border-radius: 2px;
  background: var(--accent);
  transition: opacity 0.1s, height 0.1s;
  flex-shrink: 0;
}

.voiceTime {
  font-size: 10px;
  color: var(--text3);
  font-variant-numeric: tabular-nums;
}

.voiceIcon { font-size: 14px; flex-shrink: 0; }

/* ── File attachment ── */
.fileAttach {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  text-decoration: none;
  color: inherit;
  transition: opacity 0.15s;
  min-width: 200px;
}
.fileAttach:hover { opacity: 0.8; }

.fileIcon {
  width: 40px; height: 40px;
  border-radius: 10px;
  background: rgba(255,255,255,0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  position: relative;
}

.fileExt {
  position: absolute;
  bottom: 3px;
  font-size: 8px;
  font-weight: 700;
  color: var(--accent);
  letter-spacing: -0.5px;
}

.fileInfo {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
  overflow: hidden;
}

.fileName {
  font-size: 13px;
  font-weight: 500;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.fileSize {
  font-size: 10px;
  opacity: 0.6;
}

.fileDown {
  width: 28px; height: 28px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255,255,255,0.1);
  flex-shrink: 0;
}

/* ── Lightbox ── */
.lightboxOverlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.92);
  z-index: 9500;
  display: flex;
  flex-direction: column;
  animation: fadeIn 0.2s ease;
  backdrop-filter: blur(4px);
}

@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

.lightboxHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 20px;
  background: rgba(0,0,0,0.5);
  flex-shrink: 0;
}

.lightboxName {
  font-size: 14px;
  font-weight: 500;
  color: rgba(255,255,255,0.8);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 60%;
}

.lightboxActions { display: flex; gap: 8px; }

.lightboxBtn {
  width: 36px; height: 36px;
  border-radius: 10px;
  background: rgba(255,255,255,0.1);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  transition: background 0.15s;
}
.lightboxBtn:hover { background: rgba(255,255,255,0.2); }

.lightboxContent {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
  padding: 20px 60px;
}

.lightboxMedia {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
  border-radius: 8px;
  animation: zoomIn 0.2s ease;
  user-select: none;
}

@keyframes zoomIn {
  from { opacity: 0; transform: scale(0.94); }
  to   { opacity: 1; transform: scale(1); }
}

.lightboxNav {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  width: 44px; height: 44px;
  border-radius: 50%;
  background: rgba(255,255,255,0.15);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.15s, transform 0.15s;
  z-index: 10;
}
.lightboxNav:hover { background: rgba(255,255,255,0.3); transform: translateY(-50%) scale(1.08); }
.lightboxPrev { left: 12px; }
.lightboxNext { right: 12px; }

.lightboxFooter {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 20px;
  background: rgba(0,0,0,0.5);
  font-size: 12px;
  color: rgba(255,255,255,0.5);
  flex-shrink: 0;
}
.lightboxSender { color: rgba(255,255,255,0.7); font-weight: 500; }

/* ── Context menu ── */
.ctxMenu {
  position: fixed;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: 12px;
  box-shadow: 0 8px 32px rgba(0,0,0,0.55);
  z-index: 1000;
  overflow: hidden;
  min-width: 175px;
  animation: msgIn 0.1s ease;
}
.ctxMenu button {
  display: flex;
  align-items: center;
  gap: 8px;
  width: 100%;
  text-align: left;
  padding: 9px 14px;
  font-size: 13px;
  color: var(--text);
  transition: background 0.1s;
}
.ctxMenu button svg { color: var(--text3); flex-shrink: 0; }
.ctxMenu button:hover { background: var(--bg4); }
.ctxDanger { color: #ef4444 !important; }
.ctxDanger svg { color: #ef4444 !important; }

/* ── Typing ── */
.typing {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--text3);
  padding: 4px 0;
  animation: msgIn 0.2s ease;
}

.typingDots {
  display: flex;
  gap: 3px;
  align-items: center;
}
.typingDots span {
  width: 5px; height: 5px;
  border-radius: 50%;
  background: var(--text3);
  animation: blink 1.2s infinite;
}
.typingDots span:nth-child(2) { animation-delay: 0.2s; }
.typingDots span:nth-child(3) { animation-delay: 0.4s; }

@keyframes blink { 0%,100% { opacity: 1; } 50% { opacity: 0.2; } }

/* ── Pinned panel ── */
.pinnedPanel {
  position: absolute;
  top: 52px;
  right: 0;
  width: 300px;
  background: var(--bg2);
  border-left: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  border-radius: 0 0 0 14px;
  box-shadow: -4px 4px 24px rgba(0,0,0,0.3);
  z-index: 10;
  animation: msgIn 0.2s ease;
  max-height: 400px;
  display: flex;
  flex-direction: column;
}

.pinnedHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  font-size: 13px;
  font-weight: 600;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.pinnedHeader button { color: var(--text3); }
.pinnedHeader button:hover { color: var(--text); }

.pinnedList { padding: 8px; overflow-y: auto; flex: 1; }
.pinnedEmpty { color: var(--text3); font-size: 13px; padding: 8px; text-align: center; }

.pinnedMsg {
  padding: 8px;
  border-radius: 8px;
  background: var(--bg3);
  margin-bottom: 4px;
  font-size: 13px;
  display: flex;
  gap: 4px;
}
.pinnedSender { font-weight: 600; color: var(--accent); flex-shrink: 0; }
.pinnedContent { color: var(--text2); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

